-- ============================================================
-- RECETAS PERFUM MUA: 590 extractos x 3 tamanos = 1.770 productos terminados
--   Sede 1: 239 extractos + 717 PERF + 2.151 recetas BOM
--   Sede 2: 351 extractos + 1.053 PERF + 3.159 recetas BOM
-- Tenant: d46bec36-5259-4b5b-83c7-01f1e6ea5dcd (Perfum Mua)
-- Precios: 30ML=$22.000 | 50ML=$38.000 | 100ML=$75.000
-- BOM:     30ML = 13 ext + 1 env + 1 caja
--          50ML = 22 ext + 1 env + 1 caja
--          100ML = 43 ext + 1 env + 1 caja
-- Ejecutar: mysql -u root -p stockpro_db < recetasperfummua.sql
-- NOTA: Requiere que inventario_perfummua.sql ya haya sido ejecutado
-- ============================================================

USE stockpro_db;

-- ============================================================
-- 1. TABLA DE RECETAS (crear si no existe)
-- ============================================================
CREATE TABLE IF NOT EXISTS product_recipes (
    id VARCHAR(36) PRIMARY KEY,
    tenant_id VARCHAR(36) NOT NULL,
    product_id VARCHAR(36) NOT NULL,
    ingredient_id VARCHAR(36) NOT NULL,
    quantity DECIMAL(10,3) NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE,
    FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE CASCADE,
    FOREIGN KEY (ingredient_id) REFERENCES products(id) ON DELETE RESTRICT,
    INDEX idx_recipe_product (product_id),
    INDEX idx_recipe_tenant (tenant_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ============================================================
-- 2. VARIABLES
-- ============================================================
SET @tid = 'd46bec36-5259-4b5b-83c7-01f1e6ea5dcd' COLLATE utf8mb4_unicode_ci;

-- ============================================================
-- 3. CATEGORIA PERFUMERIA (si no existe)
-- ============================================================

-- ============================================================
-- 4. LIMPIAR DATOS PREVIOS (idempotente — seguro para re-ejecutar)
-- ============================================================
DELETE FROM product_recipes WHERE tenant_id = @tid;
DELETE FROM products WHERE tenant_id = @tid AND id LIKE 'PERF-%';
DELETE FROM products WHERE tenant_id = @tid AND articulo LIKE 'EXT-%';

