-- ============================================================

-- 9. VERIFICACION
-- ============================================================
SELECT CONCAT('Productos terminados creados: ', COUNT(*)) AS resultado
FROM products WHERE tenant_id = @tid AND id LIKE 'PERF-%';

SELECT p.name AS Perfume, p.presentation AS Presentacion,
    CONCAT('$', FORMAT(p.sale_price, 0)) AS 'Precio Venta'
FROM products p
WHERE p.tenant_id = @tid AND p.id LIKE 'PERF-s1-001-%'
ORDER BY p.sale_price;

SELECT CONCAT('Extractos sede 1: ', COUNT(*)) AS resultado FROM products WHERE tenant_id = @tid AND id LIKE 'prod-pm-s1-%';
SELECT CONCAT('Extractos sede 2: ', COUNT(*)) AS resultado FROM products WHERE tenant_id = @tid AND id LIKE 'prod-pm-s2-%' AND articulo LIKE 'EXT-%';
SELECT CONCAT('Recetas BOM: ', COUNT(*)) AS resultado FROM product_recipes WHERE tenant_id = @tid AND product_id LIKE 'PERF-%';
SELECT 'Seed ejecutado correctamente. 1.770 perfumes + 5.310 recetas BOM cargados.' AS RESULTADO;